8: // migration_utils.go contains shared utility functions used across multiple schema version migrations.
9: 
10: // GetStringValue safely extracts a string value from a map, returning empty string if not found or not a string
11: func GetStringValue(m map[string]interface{}, key string, defaultValue ...string) string {
12: 	if value, ok := m[key]; ok {
13: 		if s, ok := value.(string); ok {
14: 			return s
15: 		}
16: 	}
17: 	if len(defaultValue) > 0 {
18: 		return defaultValue[0]
19: 	}
20: 	return ""
21: }
22: 
23: // GetBoolValue safely extracts a boolean value from a map, returning false if not found or not a boolean
24: func GetBoolValue(m map[string]interface{}, key string) bool {
25: 	if value, ok := m[key]; ok {
26: 		if b, ok := value.(bool); ok {
27: 			return b
28: 		}
29: 	}
30: 	return false
31: }
32: 
33: // GetIntValue safely extracts an integer value from a map, returning defaultValue if not found or not convertible
34: func GetIntValue(m map[string]interface{}, key string, defaultValue int) int {
35: 	if value, ok := m[key]; ok {
36: 		if i, ok := ConvertToInt(value); ok {
37: 			return i
38: 		}
39: 	}
40: 	return defaultValue
41: }
42: 
43: // GetFloatValue safely extracts a float value from a map, returning defaultValue if not found or not convertible
44: func GetFloatValue(m map[string]interface{}, key string, defaultValue float64) float64 {
45: 	if value, ok := m[key]; ok {
46: 		if f, ok := ConvertToFloat(value); ok {
47: 			return f
48: 		}
49: 	}
50: 	return defaultValue
51: }
52: 
53: // ConvertToFloat converts various numeric types to float64
54: func ConvertToFloat(value interface{}) (float64, bool) {
55: 	switch v := value.(type) {
56: 	case float64:
57: 		return v, true
58: 	case int:
59: 		return float64(v), true
60: 	case int64:
61: 		return float64(v), true
62: 	case float32:
63: 		return float64(v), true
64: 	case int32:
65: 		return float64(v), true
66: 	case string:
67: 		// Handle string values like "700px" - strip px suffix and parse
68: 		// This matches frontend behavior: parseInt(height.replace('px', ''), 10)
69: 		cleanStr := strings.TrimSuffix(v, "px")
70: 		if parsed, err := strconv.ParseFloat(cleanStr, 64); err == nil {
71: 			return parsed, true
72: 		}
73: 		return 0, false
74: 	default:
75: 		return 0, false
76: 	}
77: }
78: 
79: // ConvertToInt converts various numeric types to int
80: func ConvertToInt(value interface{}) (int, bool) {
81: 	switch v := value.(type) {
82: 	case int:
83: 		return v, true
84: 	case float64:
85: 		return int(v), true
86: 	case int64:
87: 		return int(v), true
88: 	case float32:
89: 		return int(v), true
90: 	case int32:
91: 		return int(v), true
92: 	default:
93: 		return 0, false
94: 	}
95: }
96: 
97: // IsArray checks if a value is an array (slice)
98: func IsArray(value interface{}) bool {
99: 	if value == nil {
100: 		return false
101: 	}
102: 	_, ok := value.([]interface{})
103: 	return ok
104: }
