106: // AngularPanelMigrations maps deprecated Angular panel types to their modern equivalents.
107: // Used by both v0→v1 and v1→v2 conversions to ensure consistent migration behavior.
108: var AngularPanelMigrations = map[string]string{
109: 	"table-old":                "table",
110: 	"singlestat":               "stat",
111: 	"grafana-singlestat-panel": "stat",
112: 	"grafana-piechart-panel":   "piechart",
113: 	"grafana-worldmap-panel":   "geomap",
114: 	"natel-discrete-panel":     "state-timeline",
115: }
116: 
117: // GetAngularPanelMigration checks if a panel type is an Angular panel and returns the new type to migrate to.
118: // Returns the new panel type if migration is needed, empty string otherwise.
119: // This handles both simple mappings and special cases like graph panel.
120: func GetAngularPanelMigration(panelType string, panel map[string]interface{}) string {
121: 	// Handle graph panel specially - it can migrate to different panel types
122: 	// based on xaxis.mode
123: 	if panelType == "graph" || panelType == "graphite" {
124: 		return GetGraphMigrationTarget(panel)
125: 	}
126: 
127: 	// Check simple Angular panel mappings
128: 	if newType, isAngular := AngularPanelMigrations[panelType]; isAngular {
129: 		return newType
130: 	}
131: 
132: 	return ""
133: }
134: 
135: // GetGraphMigrationTarget determines the target panel type for graph panel migration.
136: // Graph panels can migrate to timeseries, barchart, bargauge, or histogram depending on xaxis.mode.
137: func GetGraphMigrationTarget(panel map[string]interface{}) string {
138: 	// Default to timeseries
139: 	newType := "timeseries"
140: 
141: 	// Check xaxis mode for special cases
142: 	if xaxis, ok := panel["xaxis"].(map[string]interface{}); ok {
143: 		if mode, ok := xaxis["mode"].(string); ok {
144: 			switch mode {
145: 			case "series":
146: 				// Check legend values for bargauge vs barchart
147: 				if legend, ok := panel["legend"].(map[string]interface{}); ok {
148: 					if values, ok := legend["values"].(bool); ok && values {
149: 						newType = "bargauge"
150: 					} else {
151: 						newType = "barchart"
152: 					}
153: 				} else {
154: 					newType = "barchart"
155: 				}
156: 			case "histogram":
157: 				newType = "histogram"
158: 			}
159: 		}
160: 	}
161: 
162: 	return newType
163: }
164: 
165: // IsAngularPanelType checks if a panel type is a known Angular panel type.
166: func IsAngularPanelType(panelType string) bool {
167: 	if panelType == "graph" || panelType == "graphite" {
168: 		return true
169: 	}
170: 	_, isAngular := AngularPanelMigrations[panelType]
171: 	return isAngular
172: }
