8: // Shared utility functions for datasource migrations across different schema versions.
9: // These functions handle the common logic for migrating datasource references from
10: // string names/UIDs to structured reference objects with uid, type, and apiVersion.
11: 
12: // cachedIndexProvider wraps a DataSourceIndexProvider with time-based caching.
13: type cachedIndexProvider struct {
14: 	*cachedProvider[*DatasourceIndex]
15: }
16: 
17: // Index returns the cached index if it's still valid (< TTL old), otherwise rebuilds it.
18: func (p *cachedIndexProvider) Index(ctx context.Context) *DatasourceIndex {
19: 	return p.Get(ctx)
20: }
21: 
22: // cachedLibraryElementProvider wraps a LibraryElementIndexProvider with time-based caching.
23: type cachedLibraryElementProvider struct {
24: 	*cachedProvider[[]LibraryElementInfo]
25: }
26: 
27: func (p *cachedLibraryElementProvider) GetLibraryElementInfo(ctx context.Context) []LibraryElementInfo {
28: 	return p.Get(ctx)
29: }
30: 
31: // WrapIndexProviderWithCache wraps a DataSourceIndexProvider to cache indexes with a configurable TTL.
32: func WrapIndexProviderWithCache(provider DataSourceIndexProvider, cacheTTL time.Duration) DataSourceIndexProvider {
33: 	if provider == nil || cacheTTL <= 0 {
34: 		return provider
35: 	}
36: 	return &cachedIndexProvider{
37: 		newCachedProvider[*DatasourceIndex](provider.Index, defaultCacheSize, cacheTTL),
38: 	}
39: }
40: 
41: // WrapLibraryElementProviderWithCache wraps a LibraryElementIndexProvider to cache library elements with a configurable TTL.
42: func WrapLibraryElementProviderWithCache(provider LibraryElementIndexProvider, cacheTTL time.Duration) LibraryElementIndexProvider {
43: 	if provider == nil || cacheTTL <= 0 {
44: 		return provider
45: 	}
46: 	return &cachedLibraryElementProvider{
47: 		newCachedProvider[[]LibraryElementInfo](provider.GetLibraryElementInfo, defaultCacheSize, cacheTTL),
48: 	}
49: }
50: 
51: // DatasourceIndex provides O(1) lookup of datasources by name or UID.
52: type DatasourceIndex struct {
53: 	ByName    map[string]*DataSourceInfo
54: 	ByUID     map[string]*DataSourceInfo
55: 	DefaultDS *DataSourceInfo
56: }
57: 
58: // NewDatasourceIndex creates an index from a list of datasources.
59: // Iterates once through the list to build name and UID maps for O(1) lookups.
60: func NewDatasourceIndex(datasources []DataSourceInfo) *DatasourceIndex {
61: 	idx := &DatasourceIndex{
62: 		ByName: make(map[string]*DataSourceInfo, len(datasources)),
63: 		ByUID:  make(map[string]*DataSourceInfo, len(datasources)),
64: 	}
65: 
66: 	for i := range datasources {
67: 		ds := &datasources[i]
68: 
69: 		// Index by name if present
70: 		if ds.Name != "" {
71: 			idx.ByName[ds.Name] = ds
72: 		}
73: 
74: 		// Index by UID if present
75: 		if ds.UID != "" {
76: 			idx.ByUID[ds.UID] = ds
77: 		}
78: 
79: 		// Track default datasource
80: 		if ds.Default {
81: 			idx.DefaultDS = ds
82: 		}
83: 	}
84: 
85: 	return idx
86: }
87: 
88: // Lookup finds a datasource by name or UID string.
89: // Returns the datasource info if found, nil otherwise.
90: func (idx *DatasourceIndex) Lookup(nameOrUID string) *DataSourceInfo {
91: 	// Try name first (most common in legacy dashboards)
92: 	if ds := idx.ByName[nameOrUID]; ds != nil {
93: 		return ds
94: 	}
95: 	// Try UID second
96: 	return idx.ByUID[nameOrUID]
97: }
98: 
99: func (idx *DatasourceIndex) LookupByUID(uid string) *DataSourceInfo {
100: 	return idx.ByUID[uid]
101: }
102: 
103: func (idx *DatasourceIndex) LookupByName(name string) *DataSourceInfo {
104: 	return idx.ByName[name]
105: }
106: 
107: // GetDefault returns the default datasource, if one exists.
108: func (idx *DatasourceIndex) GetDefault() *DataSourceInfo {
109: 	return idx.DefaultDS
110: }
111: 
112: // GetDataSourceRef creates a datasource reference object with uid, type and optional apiVersion
113: func GetDataSourceRef(ds *DataSourceInfo) map[string]interface{} {
114: 	if ds == nil {
115: 		return nil
116: 	}
117: 	ref := map[string]interface{}{
118: 		"uid":  ds.UID,
119: 		"type": ds.Type,
120: 	}
121: 	if ds.APIVersion != "" {
122: 		ref["apiVersion"] = ds.APIVersion
123: 	}
124: 	return ref
125: }
126: 
127: // isDataSourceRef checks if the object is a valid DataSourceRef (has uid or type)
128: // Matches the frontend isDataSourceRef function in datasource.ts
129: func isDataSourceRef(ref interface{}) bool {
130: 	dsRef, ok := ref.(map[string]interface{})
131: 	if !ok {
132: 		return false
133: 	}
134: 
135: 	hasUID := false
136: 	if uid, exists := dsRef["uid"]; exists {
137: 		if uidStr, ok := uid.(string); ok && uidStr != "" {
138: 			hasUID = true
139: 		}
140: 	}
141: 
142: 	hasType := false
143: 	if typ, exists := dsRef["type"]; exists {
144: 		if typStr, ok := typ.(string); ok && typStr != "" {
145: 			hasType = true
146: 		}
147: 	}
148: 
149: 	return hasUID || hasType
150: }
151: 
152: // MigrateDatasourceNameToRef converts a datasource name/uid string to a reference object
153: // Matches the frontend migrateDatasourceNameToRef function in DashboardMigrator.ts
154: // Options:
155: //   - returnDefaultAsNull: if true, returns nil for "default" datasources (used in V33)
156: //   - returnDefaultAsNull: if false, returns reference for "default" datasources (used in V36)
157: func MigrateDatasourceNameToRef(nameOrRef interface{}, options map[string]bool, index *DatasourceIndex) map[string]interface{} {
158: 	if options["returnDefaultAsNull"] && (nameOrRef == nil || nameOrRef == "default") {
159: 		return nil
160: 	}
161: 
162: 	// Frontend: if (isDataSourceRef(nameOrRef)) { return nameOrRef; }
163: 	if isDataSourceRef(nameOrRef) {
164: 		return nameOrRef.(map[string]interface{})
165: 	}
166: 
167: 	// Look up datasource by name/UID
168: 	if nameOrRef == nil || nameOrRef == "default" {
169: 		if ds := index.GetDefault(); ds != nil {
170: 			return GetDataSourceRef(ds)
171: 		}
172: 	}
173: 
174: 	// Check if it's a string name/UID
175: 	if str, ok := nameOrRef.(string); ok {
176: 		// Handle empty string case
177: 		if str == "" {
178: 			// Empty string should return {} (frontend behavior)
179: 			return map[string]interface{}{}
180: 		}
181: 
182: 		if ds := index.Lookup(str); ds != nil {
183: 			return GetDataSourceRef(ds)
184: 		}
185: 
186: 		// Unknown datasource name should be preserved as UID-only reference
187: 		return map[string]interface{}{
188: 			"uid": str,
189: 		}
190: 	}
191: 
192: 	return nil
193: }
